# --- static geometry (redefined locally; never import simulator internals) ---
GRID = 52
WALK_MIN = 1
WALK_MAX = 50
INF = 1 << 29

# Tunable planner constants (no wall-clock guard; compute is bounded by these).
WINDOW = 28  # space-time reservation horizon (ticks)
NODE_CAP = 2500  # max A* expansions per robot before greedy fallback
WAIT_CAP = 30  # cap on starvation boost in the priority key
FLOW_PENALTY = 0.3  # Soft preference for traffic directions

_DIRS = (
    (Action.UP, 0, -1),
    (Action.DOWN, 0, 1),
    (Action.LEFT, -1, 0),
    (Action.RIGHT, 1, 0),
)


def _node(x: int, y: int) -> int:
    return y * GRID + x


def _base_entry_cells() -> set[tuple[int, int]]:
    """The 96 base-entry cells that MUST stay empty (drop/spawn cells)."""
    entries: set[tuple[int, int]] = set()
    for x in range(3, 50, 2):  # top    x=3,5,..,49 -> (x,1)
        entries.add((x, 1))
    for x in range(2, 49, 2):  # bottom x=2,4,..,48 -> (x,50)
        entries.add((x, 50))
    for y in range(2, 49, 2):  # left   y=2,4,..,48 -> (1,y)
        entries.add((1, y))
    for y in range(3, 50, 2):  # right  y=3,5,..,49 -> (50,y)
        entries.add((50, y))
    return entries


